import{_ as a,o as i,c as n,ag as r}from"./chunks/framework.ByAj6Cie.js";const u=JSON.parse('{"title":"Señales 4-20 mA","description":"","frontmatter":{},"headers":[],"relativePath":"es/instrumentation/4-20ma-signals.md","filePath":"es/instrumentation/4-20ma-signals.md"}'),o={name:"es/instrumentation/4-20ma-signals.md"};function l(s,e,t,d,c,p){return i(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="senales-4-20-ma" tabindex="-1">Señales 4-20 mA <a class="header-anchor" href="#senales-4-20-ma" aria-label="Permalink to &quot;Señales 4-20 mA&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>4-20 mA es una señal analógica estándar utilizada en instrumentación industrial para transmitir variables de proceso.</p><p>Representa un valor medido como una corriente eléctrica, donde 4 mA corresponde al valor mínimo y 20 mA al valor máximo.</p><p>Este estándar se utiliza ampliamente debido a su confiabilidad y resistencia al ruido.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de las señales 4-20 mA es proporcionar una forma robusta y consistente de transmitir mediciones analógicas a distancia.</p><p>Se utiliza para:</p><ul><li>Enviar variables de proceso desde instrumentos de campo a los sistemas de control</li><li>Asegurar la integridad de la señal en entornos industriales</li><li>Estandarizar la comunicación entre dispositivos</li></ul><p>Es un elemento clave en los sistemas de instrumentación analógica.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Un transmisor convierte una medición física en una señal de corriente dentro del rango 4-20 mA.</p><h3 id="rango-de-senal" tabindex="-1">Rango de señal <a class="header-anchor" href="#rango-de-senal" aria-label="Permalink to &quot;Rango de señal&quot;">​</a></h3><ul><li>4 mA representa el valor mínimo de medición</li><li>20 mA representa el valor máximo de medición</li></ul><p>Los valores entre 4 y 20 mA corresponden linealmente a la variable medida.</p><h3 id="cero-vivo" tabindex="-1">Cero vivo <a class="header-anchor" href="#cero-vivo" aria-label="Permalink to &quot;Cero vivo&quot;">​</a></h3><p>El uso de 4 mA en lugar de 0 mA permite la detección de fallas.</p><ul><li>0 mA indica un cable roto o pérdida de señal</li><li>Valores por debajo de 4 mA pueden indicar una condición de falla</li></ul><p>Esto mejora la confiabilidad del sistema.</p><h3 id="lazo-de-corriente" tabindex="-1">Lazo de corriente <a class="header-anchor" href="#lazo-de-corriente" aria-label="Permalink to &quot;Lazo de corriente&quot;">​</a></h3><p>La señal se transmite a través de un lazo de corriente.</p><ul><li>La corriente permanece constante independientemente de la resistencia del cable</li><li>El voltaje varía según sea necesario para mantener la corriente</li></ul><p>Esto hace que la señal sea menos sensible al ruido y a las caídas de voltaje.</p><h3 id="conversion" tabindex="-1">Conversión <a class="header-anchor" href="#conversion" aria-label="Permalink to &quot;Conversión&quot;">​</a></h3><p>En el extremo receptor, la corriente se convierte en un valor utilizable.</p><ul><li>Los módulos de entrada analógica del PLC miden la corriente</li><li>La señal se escala a unidades de ingeniería</li></ul><p>Esto permite la integración en la lógica de control.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las señales 4-20 mA se utilizan en la mayoría de los procesos industriales.</p><p>Las aplicaciones típicas incluyen:</p><ul><li>Transmisores de temperatura</li><li>Transmisores de presión</li><li>Dispositivos de medición de flujo</li><li>Sensores de nivel</li></ul><p>Son estándar en los sistemas de control de procesos.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><p>Se requiere un escalamiento adecuado para convertir la corriente en valores significativos.</p><p>La fuente de alimentación del lazo debe ser suficiente para todos los dispositivos en el lazo.</p><p>La selección y el tendido del cable afectan la calidad de la señal.</p><p>Puede requerirse seguridad intrínseca en entornos peligrosos.</p><p>Debe verificarse la compatibilidad del módulo de entrada.</p><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><p>Un error común es el escalamiento incorrecto de la señal en el PLC. Siempre verifique el rango de medición.</p><p>Revise cuidadosamente el cableado del lazo. Conexiones incorrectas pueden impedir la transmisión de la señal.</p><p>Utilice una puesta a tierra y blindaje adecuados para reducir la interferencia.</p><p>Verifique la corriente del lazo durante la puesta en marcha para confirmar el funcionamiento correcto.</p><p>Etiquete los rangos de señal claramente para evitar confusiones durante el mantenimiento.</p>',44)])])}const h=a(o,[["render",l]]);export{u as __pageData,h as default};
